SELECT COUNT(*)
FROM extra_charge_order
WHERE user_id = #{userId}

SELECT eco.id, eco.user_id, eco.order_number, eco.amount, eco.content, 
       eco.payment_status, eco.payment_time, eco.create_time, eco.update_time,
       u.username
FROM extra_charge_order eco
LEFT JOIN user u ON eco.user_id = u.id
WHERE eco.user_id = #{userId}

    AND eco.payment_status = #{paymentStatus}

ORDER BY eco.create_time DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(*)
FROM extra_charge_order
WHERE user_id = #{userId}

    AND payment_status = #{paymentStatus}
